arguments.new_str:
using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools ---
var tools = new ResearchTools();

// --- Build the agent ---
var agent = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient()
    .AsAIAgent(
        instructions: """
            You are a research agent. When given a topic you must:
            1. Search the web for information using the web_search tool (perform 2-4 searches with varied queries).
            2. Save key findings using the save_note tool as you go.
            3. After gathering enough information, call get_notes to review everything you saved.
            4. Provide a comprehensive summary of your research with key findings and sources.
            Be thorough but concise. Always cite your sources.
            """,
        name: "ResearchAgent",
        description: "An agent that researches topics by searching the web and taking notes.",
        tools:
        [
            AIFunctionFactory.Create(tools.WebSearch),
            AIFunctionFactory.Create(tools.SaveNote),
            AIFunctionFactory.Create(tools.GetNotes),
        ]);

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync("research-session");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var result = await agent.RunAsync($"Research this topic: {topic}", session, runOptions);

// --- Display results ---
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════\n");

foreach (var message in result.Messages)
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
    {
        Console.WriteLine(message.Text);
    }
}

Console.WriteLine($"\n───────────────────────────────────────────");
Console.WriteLine($"  Notes collected: {tools.NoteCount}");
Console.WriteLine($"  Searches performed: {tools.SearchCount}");
Console.WriteLine($"───────────────────────────────────────────");

return 0;

// ==========================================================================
//  Tool implementations
// ==========================================================================

sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http = new();
    private int _searchCount;

    public int NoteCount => _notes.Count;
    public int SearchCount => _searchCount;

    [Description("Search the web for information on a query. Returns a list of search result snippets.")]
    public async Task<string> WebSearch(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        Interlocked.Increment(ref _searchCount);
        Console.WriteLine($"  🔍 Searching: {query}");

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var response = await _http.SendAsync(request, cancellationToken);
            var html = await response.Content.ReadAsStringAsync(cancellationToken);

            var results = ParseDuckDuckGoResults(html);
            if (results.Count == 0)
                return $"No results found for '{query}'.";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for '{query}':");
            for (var i = 0; i < Math.Min(results.Count, 5); i++)
            {
                sb.AppendLine($"\n[{i + 1}] {results[i].Title}");
                sb.AppendLine($"    URL: {results[i].Url}");
                sb.AppendLine($"    {results[i].Snippet}");
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    [Description("Save a research note with a key finding. Use this to record important information as you discover it.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes to review before writing the summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"All saved notes ({_notes.Count}):");
